import { useState } from "react";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);
    const [loading, setLoading] = useState(false);

    const analyzeResume = async () => {
        if (!resumeText) return;

        setLoading(true);

        const res = await fetch("http://localhost:5000/analyze", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({ resumeText, jobDescription })
        });

        const data = await res.json();
        setAnalysis(data);
        setLoading(false);
    };

    const tagStyle = (bg, color) => ({
        padding: "8px 14px",
        borderRadius: "20px",
        margin: "6px",
        fontSize: "14px",
        fontWeight: "600",
        background: bg,
        color: color,
        transition: "transform 0.2s",
        cursor: "default"
    });

    return (
        <div style={{
            minHeight: "100vh",
            background: "linear-gradient(135deg, #667eea, #764ba2)",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            fontFamily: "sans-serif",
            padding: "20px"
        }}>
            <div style={{
                width: "900px",
                background: "white",
                padding: "30px",
                borderRadius: "12px",
                boxShadow: "0 10px 30px rgba(0,0,0,0.2)"
            }}>
                <h1 style={{ textAlign: "center" }}>AI Resume Analyzer 🚀</h1>

                <textarea
                    placeholder="Paste Resume..."
                    value={resumeText}
                    onChange={(e) => setResumeText(e.target.value)}
                    style={inputStyle}
                />

                <textarea
                    placeholder="Paste Job Description..."
                    value={jobDescription}
                    onChange={(e) => setJobDescription(e.target.value)}
                    style={inputStyle}
                />

                <div style={{ textAlign: "center" }}>
                    <button
                        onClick={analyzeResume}
                        style={buttonStyle}
                    >
                        {loading ? "Analyzing..." : "Analyze Match"}
                    </button>
                </div>

                {analysis && (
                    <div style={{ marginTop: "25px" }}>
                        <h2>Role: {analysis.role}</h2>

                        {/* Score Bar */}
                        <div style={{ margin: "20px 0" }}>
                            <h3>Score: {analysis.score}%</h3>
                            <div style={{
                                height: "20px",
                                background: "#eee",
                                borderRadius: "20px",
                                overflow: "hidden"
                            }}>
                                <div style={{
                                    width: `${analysis.score}%`,
                                    height: "100%",
                                    background: analysis.score > 75 ? "#28a745" :
                                        analysis.score > 50 ? "#ffc107" : "#dc3545",
                                    transition: "width 1s ease"
                                }} />
                            </div>
                        </div>

                        {/* Required */}
                        <Section title="Required Skills">
                            {analysis.requiredKeywords.map((s, i) => (
                                <span key={i} style={tagStyle("#ddd", "#333")}>{s}</span>
                            ))}
                        </Section>

                        {/* Matched */}
                        <Section title="Matched Skills">
                            {analysis.matchedSkills.map((s, i) => (
                                <span key={i} style={tagStyle("#d4edda", "#155724")}>{s}</span>
                            ))}
                        </Section>

                        {/* Missing */}
                        <Section title="Missing Skills">
                            {analysis.missingSkills.map((s, i) => (
                                <span key={i} style={tagStyle("#f8d7da", "#721c24")}>{s}</span>
                            ))}
                        </Section>

                        {/* Suggestions */}
                        <Section title="Suggestions">
                            <ul>
                                {analysis.suggestions.map((s, i) => (
                                    <li key={i}>{s}</li>
                                ))}
                            </ul>
                        </Section>

                    </div>
                )}
            </div>
        </div>
    );
}

const Section = ({ title, children }) => (
    <div style={{
        background: "#f8f9fa",
        padding: "15px",
        borderRadius: "8px",
        marginBottom: "15px"
    }}>
        <h3>{title}</h3>
        <div style={{ display: "flex", flexWrap: "wrap" }}>
            {children}
        </div>
    </div>
);

const inputStyle = {
    width: "100%",
    height: "120px",
    marginTop: "10px",
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #ccc",
    resize: "none"
};

const buttonStyle = {
    marginTop: "15px",
    padding: "12px 20px",
    background: "#007bff",
    color: "white",
    border: "none",
    borderRadius: "8px",
    fontSize: "16px",
    cursor: "pointer",
    transition: "0.3s"
};

export default App;
